import { updateScaleByTransform } from '../../../data-selection/chart/tools/transform-scale';
import { getPropVal } from '../../../../utils/zcutils';
import { d3_scaleLinear, d3_zoomIdentity } from '../../../../core/d3-constants';

export function applyZoomTransform(scaleObj, type, orient, reversed, chart, axisObj) {
    let plotZoom = chart.behaviouralEvents && getPropVal(chart.behaviouralEvents.eventManager, 'behaviours.PLOT_ZOOM');

    if (plotZoom && plotZoom.types && plotZoom.types[type] === true) {
        let transform = plotZoom.instance.getTransform(),
            t0 = { [type]: axisObj },
            // #ZC2260 $newTransform
            newTransform = getZoomTransformFromAxis(transform.k, t0.x, t0.y, chart);

        // apply the transform on redraw
        updateScaleByTransform(axisObj, type, newTransform);
    }
    return scaleObj;
}

/**
 *
 * @param k
 * @param xAxis
 * @param yAxis
 * @param chart
 * @return {*}
 */
export function getZoomTransformFromAxis(k, xAxis, yAxis, chart) {
    let x = 0,
        y = 0;

    if (xAxis) {
        x = xAxis.baseZoomScale(xAxis.zoomDomain[0]);
    }
    if (yAxis) {
        y = yAxis.baseZoomScale(yAxis.zoomDomain[0]);
    }
    return d3_zoomIdentity.scale(k).translate(-x, -y);
}

/**
 *
 * @param axisObj
 * @param chart
 */
export function createZoomScale(axisObj, chart) {
    // create a normal scale for every axis and apply that when resize
    let zoomEnabled = getPropVal(chart.systemConf, 'chart.zoom.enabled') === true;
    if (zoomEnabled) {
        axisObj.zoomScale = d3_scaleLinear()
            .range([0, chart.axes.rotated ? chart.plotarea.height : chart.plotarea.width])
            .domain([0, 100]);
        axisObj.baseZoomScale = axisObj.zoomScale.copy();
    }
}
